from typing import List

#
# 代码中的类名、方法名、参数名已经指定，请勿修改，直接返回方法规定的值即可
#
# 找出所有出现次数大于等于 3 次的日志标识
# @param logs string字符串一维数组 日志标识数组
# @return string字符串一维数组
#
class Solution:
    def findAnomalyLogs(self, logs: List[str]) -> List[str]:
        cnt = {}
        first = {}

        # 统计每个日志标识出现次数，并记录首次出现位置
        for i in range(len(logs)):
            s = logs[i]
            cnt[s] = cnt.get(s, 0) + 1
            if s not in first:
                first[s] = i

        ans = []

        # 筛选出现次数大于等于 3 次的日志标识
        for s in cnt:
            if cnt[s] >= 3:
                ans.append(s)

        # 按出现次数降序，首次出现位置升序排序
        ans.sort(key=lambda x: (-cnt[x], first[x]))

        return ans
