import java.util.*;

public class Solution {
    /**
     * 代码中的类名、方法名、参数名已经指定，请勿修改，直接返回方法规定的值即可
     *
     * 找出所有出现次数大于等于 3 次的日志标识
     * @param logs string字符串一维数组 日志标识数组
     * @return string字符串一维数组
     */
    public String[] findAnomalyLogs(String[] logs) {
        Map<String, Integer> cnt = new HashMap<>();
        Map<String, Integer> first = new HashMap<>();

        // 统计每个日志标识出现次数，并记录首次出现位置
        for (int i = 0; i < logs.length; i++) {
            String s = logs[i];
            cnt.put(s, cnt.getOrDefault(s, 0) + 1);
            if (!first.containsKey(s)) {
                first.put(s, i);
            }
        }

        List<String> ans = new ArrayList<>();

        // 筛选出现次数大于等于 3 次的日志标识
        for (String s : cnt.keySet()) {
            if (cnt.get(s) >= 3) {
                ans.add(s);
            }
        }

        // 按出现次数降序，首次出现位置升序排序
        Collections.sort(ans, new Comparator<String>() {
            public int compare(String a, String b) {
                if (!cnt.get(a).equals(cnt.get(b))) {
                    return cnt.get(b) - cnt.get(a);
                }
                return first.get(a) - first.get(b);
            }
        });

        // 将列表转为数组返回
        String[] res = new String[ans.size()];
        for (int i = 0; i < ans.size(); i++) {
            res[i] = ans.get(i);
        }

        return res;
    }
}
