var findAnomalyLogs = function(logs) {
    const cnt = new Map();
    const first = new Map();

    // 统计每个日志标识出现次数，并记录首次出现位置
    for (let i = 0; i < logs.length; i++) {
        const log = logs[i];
        cnt.set(log, (cnt.get(log) || 0) + 1);
        if (!first.has(log)) first.set(log, i);
    }

    const result = [];

    // 筛选出现次数大于等于 3 次的日志标识
    for (const [log, count] of cnt) {
        if (count >= 3) result.push(log);
    }

    // 排序：出现次数降序，首次出现位置升序
    result.sort((a, b) => {
        const diff = cnt.get(b) - cnt.get(a);
        if (diff !== 0) return diff;
        return first.get(a) - first.get(b);
    });

    return result;
};
